import numpy as np
from dataclasses import dataclass, field
from typing import Callable, List, Dict, Any, Optional, Tuple
import math

WARP_SIZE = 32
TRANSACTION_SIZE = 128  # bytes
NUM_BANKS = 32
BANK_WIDTH = 4  # bytes


@dataclass
class ThreadContext:
    """Represents the execution context of a single GPU thread."""
    threadIdx: int
    blockIdx: int
    blockDim: int
    gridDim: int

    @property
    def global_id(self) -> int:
        return self.blockIdx * self.blockDim + self.threadIdx


@dataclass
class KernelStats:
    """Tracks performance metrics for a kernel execution."""
    global_memory_transactions: int = 0
    bank_conflicts: int = 0
    total_threads_launched: int = 0
    active_threads: int = 0
    warps_executed: int = 0
    divergent_warps: int = 0


class SharedMemory:
    """Simulates GPU shared memory with bank conflict detection."""

    def __init__(self, size_bytes: int = 49152):
        self.size = size_bytes
        self.data = np.zeros(size_bytes, dtype=np.uint8)
        self.total_conflicts = 0
        self.access_log: List[Dict] = []

    def access(self, addresses: List[int]) -> Dict[str, Any]:
        if not addresses:
            return {'conflicts': 0, 'bank_histogram': {}, 'pattern': 'conflict_free'}

        # Map each address to its bank
        bank_map: Dict[int, List[int]] = {}  # bank_id -> [addresses]
        for addr in addresses:
            bank = (addr // BANK_WIDTH) % NUM_BANKS
            if bank not in bank_map:
                bank_map[bank] = []
            bank_map[bank].append(addr)

        bank_histogram = {bank: len(addrs) for bank, addrs in bank_map.items()}

        total_conflicts = 0
        has_broadcast = False
        has_conflict = False

        for bank, addrs in bank_map.items():
            if len(addrs) > 1:
                unique_addrs = set(addrs)
                if len(unique_addrs) == 1:
                    # All accesses to same address: broadcast, no conflict
                    has_broadcast = True
                else:
                    # Different addresses in same bank: conflict
                    total_conflicts += len(addrs) - 1
                    has_conflict = True

        if has_conflict:
            pattern = 'conflicted'
        elif has_broadcast:
            pattern = 'broadcast'
        else:
            pattern = 'conflict_free'

        self.total_conflicts += total_conflicts
        self.access_log.append({'addresses': addresses, 'conflicts': total_conflicts})

        return {
            'conflicts': total_conflicts,
            'bank_histogram': bank_histogram,
            'pattern': pattern
        }


class GlobalMemory:
    """Simulates GPU global memory with coalescing analysis."""

    def __init__(self, size_bytes: int = 1024 * 1024 * 1024):
        self.size = size_bytes
        self.total_transactions = 0
        self.access_log: List[Dict] = []

    def analyze_access(self, addresses: List[int], access_size: int = 4) -> Dict[str, Any]:
        if not addresses:
            return {
                'transactions': 0,
                'bytes_requested': 0,
                'bytes_transferred': 0,
                'efficiency': 1.0,
                'is_coalesced': True
            }

        # Determine which 128-byte segments are accessed
        segments = set()
        for addr in addresses:
            start_segment = addr // TRANSACTION_SIZE
            end_segment = (addr + access_size - 1) // TRANSACTION_SIZE
            for seg in range(start_segment, end_segment + 1):
                segments.add(seg)

        transactions = len(segments)
        bytes_requested = len(addresses) * access_size
        bytes_transferred = transactions * TRANSACTION_SIZE
        efficiency = bytes_requested / bytes_transferred if bytes_transferred > 0 else 1.0

        # Coalesced if we use minimum possible transactions
        min_transactions = math.ceil(bytes_requested / TRANSACTION_SIZE)
        is_coalesced = transactions <= max(min_transactions, 1)

        self.total_transactions += transactions
        self.access_log.append({
            'addresses': addresses,
            'transactions': transactions,
            'efficiency': efficiency
        })

        return {
            'transactions': transactions,
            'bytes_requested': bytes_requested,
            'bytes_transferred': bytes_transferred,
            'efficiency': efficiency,
            'is_coalesced': is_coalesced
        }


class WarpScheduler:
    """Schedules and executes threads in warps of 32."""

    def __init__(self):
        self.stats = KernelStats()
        self.shared_memory = SharedMemory()
        self.global_memory = GlobalMemory()

    def execute_warp(
        self,
        kernel_func: Callable,
        thread_contexts: List[ThreadContext],
        shared_mem: SharedMemory,
        global_mem: GlobalMemory,
        n_elements: Optional[int] = None
    ) -> Dict[str, Any]:
        warp_results = []
        shared_addresses = []
        global_addresses = []
        branches_taken = []
        active_count = 0

        for ctx in thread_contexts:
            # Check if thread is active
            if n_elements is not None and ctx.global_id >= n_elements:
                continue

            active_count += 1
            result = kernel_func(ctx, shared_mem, global_mem)
            warp_results.append(result)

            if 'shared_mem_addresses' in result:
                shared_addresses.extend(result['shared_mem_addresses'])
            if 'global_mem_addresses' in result:
                global_addresses.extend(result['global_mem_addresses'])
            if 'branch_taken' in result:
                branches_taken.append(result['branch_taken'])

        # Analyze shared memory accesses
        shared_analysis = shared_mem.access(shared_addresses) if shared_addresses else {
            'conflicts': 0, 'bank_histogram': {}, 'pattern': 'conflict_free'
        }

        # Analyze global memory accesses
        global_analysis = global_mem.analyze_access(global_addresses) if global_addresses else {
            'transactions': 0, 'bytes_requested': 0, 'bytes_transferred': 0,
            'efficiency': 1.0, 'is_coalesced': True
        }

        # Detect warp divergence
        divergent = False
        if len(branches_taken) > 1:
            divergent = len(set(branches_taken)) > 1

        # Update stats
        self.stats.warps_executed += 1
        self.stats.active_threads += active_count
        self.stats.global_memory_transactions += global_analysis['transactions']
        self.stats.bank_conflicts += shared_analysis['conflicts']
        if divergent:
            self.stats.divergent_warps += 1

        return {
            'results': warp_results,
            'active_threads': active_count,
            'shared_analysis': shared_analysis,
            'global_analysis': global_analysis,
            'divergent': divergent
        }


class GPUSimulator:
    """Top-level GPU simulator that launches kernels."""

    def __init__(self):
        self.global_memory = GlobalMemory()
        self.last_stats: Optional[KernelStats] = None
        self.results: List[Any] = []

    def launch_kernel(
        self,
        kernel_func: Callable,
        grid_dim: int,
        block_dim: int,
        n_elements: Optional[int] = None
    ) -> KernelStats:
        stats = KernelStats()
        stats.total_threads_launched = grid_dim * block_dim
        self.results = []

        scheduler = WarpScheduler()

        for block_idx in range(grid_dim):
            shared_mem = SharedMemory()

            # Create thread contexts for this block
            thread_contexts = []
            for tid in range(block_dim):
                ctx = ThreadContext(
                    threadIdx=tid,
                    blockIdx=block_idx,
                    blockDim=block_dim,
                    gridDim=grid_dim
                )
                thread_contexts.append(ctx)

            # Execute warps
            num_warps = math.ceil(block_dim / WARP_SIZE)
            for warp_idx in range(num_warps):
                start = warp_idx * WARP_SIZE
                end = min(start + WARP_SIZE, block_dim)
                warp_contexts = thread_contexts[start:end]

                warp_result = scheduler.execute_warp(
                    kernel_func, warp_contexts, shared_mem,
                    self.global_memory, n_elements
                )
                self.results.extend(warp_result.get('results', []))

        # Copy accumulated stats from scheduler
        stats.warps_executed = scheduler.stats.warps_executed
        stats.active_threads = scheduler.stats.active_threads
        stats.global_memory_transactions = scheduler.stats.global_memory_transactions
        stats.bank_conflicts = scheduler.stats.bank_conflicts
        stats.divergent_warps = scheduler.stats.divergent_warps

        self.last_stats = stats
        return stats


def simple_double_kernel(ctx, shared_mem, global_mem):
    gid = ctx.global_id
    return {
        'result': gid * 2,
        'global_mem_addresses': [gid * 4],
        'shared_mem_addresses': [],
        'branch_taken': True
    }


def strided_access_kernel(ctx, shared_mem, global_mem):
    gid = ctx.global_id
    return {
        'result': gid,
        'global_mem_addresses': [gid * 128],
        'shared_mem_addresses': [],
        'branch_taken': True
    }


def bank_conflict_kernel(ctx, shared_mem, global_mem):
    tid = ctx.threadIdx
    return {
        'result': tid,
        'global_mem_addresses': [],
        'shared_mem_addresses': [tid * 8],
        'branch_taken': True
    }


def divergent_kernel(ctx, shared_mem, global_mem):
    gid = ctx.global_id
    if gid % 2 == 0:
        return {
            'result': gid * 2,
            'global_mem_addresses': [gid * 4],
            'shared_mem_addresses': [],
            'branch_taken': True
        }
    else:
        return {
            'result': gid * 3,
            'global_mem_addresses': [gid * 4],
            'shared_mem_addresses': [],
            'branch_taken': False
        }
